For each ship order, evaluate all feasible insertion positions across all existing routes using a greedy cost-delta approach, commit the minimum cost increase insertion, and if none feasible create a new route.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type candidate struct {
		assignIdx  int
		insertPos  int // simplified: rely on AddShip internal handling
		costDelta  float64
		feasible   bool
	}
	totalOrders := len(oris)
	for orderIdx := 0; orderIdx < totalOrders; orderIdx++ {
		bestCandidate := candidate{-1, -1, 0, false}
		ori := oris[orderIdx]
		des := dess[orderIdx]
		shipID := total_ship + orderIdx
		// Try all existing assigns
		for assignIdx := 0; assignIdx < dispatch.AssignsLen; assignIdx++ {
			assign := &dispatch.Assigns[assignIdx]
			savedState := *assign // shallow copy fields we may modify; deep enough for rollback via pointer ops
			success := assign.AddShip(shipID, ori, des)
			if success {
				assign.GenRoute()
				newCost := assign.Cost
				oldCost := savedState.Cost
				costDelta := newCost - oldCost
				if !bestCandidate.feasible || costDelta < bestCandidate.costDelta {
					bestCandidate = candidate{assignIdx, -1, costDelta, true}
				}
				assign.RemoveShip(shipID)
				assign.GenRoute()
			} else {
				// Ensure clean rollback
				*assign = savedState
				assign.GenRoute()
			}
		}
		// Also consider starting a fresh empty assign if within capacity
		if dispatch.AssignsLen < MAXASSIGNS {
			assign := &dispatch.Assigns[dispatch.AssignsLen]
			savedState := *assign
			success := assign.AddShip(shipID, ori, des)
			if success {
				assign.GenRoute()
				newCost := assign.Cost
				oldCost := savedState.Cost
				costDelta := newCost - oldCost
				if !bestCandidate.feasible || costDelta < bestCandidate.costDelta {
					bestCandidate = candidate{dispatch.AssignsLen, -1, costDelta, true}
				}
				assign.RemoveShip(shipID)
				assign.GenRoute()
			} else {
				*assign = savedState
				assign.GenRoute()
			}
		}
		// Commit the best feasible insertion
		if bestCandidate.feasible {
			targetAssign := &dispatch.Assigns[bestCandidate.assignIdx]
			if targetAssign.AddShip(shipID, ori, des) {
				targetAssign.GenRoute()
				if bestCandidate.assignIdx >= dispatch.AssignsLen {
					dispatch.AssignsLen++
				}
			}
		} else {
			// Fallback: force into first assign (or create new if possible) – guaranteed path per API rule
			if dispatch.AssignsLen == 0 {
				if 0 < MAXASSIGNS {
					targetAssign := &dispatch.Assigns[0]
					if targetAssign.AddShip(shipID, ori, des) {
						targetAssign.GenRoute()
						dispatch.AssignsLen = 1
					}
				}
			} else {
				// Try sequentially until one accepts; last resort expand
				inserted := false
				for idx := 0; idx < dispatch.AssignsLen; idx++ {
					if dispatch.Assigns[idx].AddShip(shipID, ori, des) {
						dispatch.Assigns[idx].GenRoute()
						inserted = true
						break
					}
				}
				if !inserted && dispatch.AssignsLen < MAXASSIGNS {
					targetAssign := &dispatch.Assigns[dispatch.AssignsLen]
					if targetAssign.AddShip(shipID, ori, des) {
						targetAssign.GenRoute()
						dispatch.AssignsLen++
					}
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

